function getMapping(key, defaultUrl) {
	if (key != null && viewMapping[key] != undefined) {
		if(key == 'loadingSheetNew' && !urlExists(viewMapping[key]))
			return viewMapping[key + '_default'];
			
		return viewMapping[key];
	}
	
	return defaultUrl;
}

function urlExists(url) {
	var http = new XMLHttpRequest();
	http.open('HEAD', url, false);
	http.send();
	return http.status == 200;
}
